import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import './Header.css';

const Header = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [mobileSearchOpen, setMobileSearchOpen] = useState(false);

  const { user, logout, isAuthenticated } = useAuth();
  const { getCartCount } = useCart();
  const navigate = useNavigate();

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/products?search=${searchQuery}`);
      setMobileSearchOpen(false); // close after search (mobile)
    }
  };

  return (
    <header className="header">
      <div className="header-content">

        {/* Logo */}
        <Link to="/" className="logo" onClick={() => setMobileSearchOpen(false)}>
          FixNFit
        </Link>

        {/* Desktop search OR Mobile expanded search */}
        <form
          className={`search-bar ${mobileSearchOpen ? 'mobile-open' : ''}`}
          onSubmit={handleSearch}
        >
          <input
            type="text"
            placeholder="Search for spare parts..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            autoFocus={mobileSearchOpen}
          />
          <button type="submit" className="search-btn">Search</button>

          {/* Close icon (mobile only) */}
          <button
            type="button"
            className="search-close"
            onClick={() => setMobileSearchOpen(false)}
          >
            ✕
          </button>
        </form>

        {/* Right actions */}
        <div className="header-actions">

          {/* Mobile search icon */}
          <button
            className="mobile-search-icon"
            onClick={() => setMobileSearchOpen(true)}
          >
            🔍
          </button>

          {isAuthenticated ? (
            <span className="user-name">Hi, {user?.name}</span>
          ) : (
            <Link to="/login" className="btn btn-secondary">Login</Link>
          )}

          <Link to="/cart" className="cart-icon">
            🛒
            {getCartCount() > 0 && (
              <span className="cart-badge">{getCartCount()}</span>
            )}
          </Link>
        </div>
      </div>
    </header>
  );
};

export default Header;
